// Validate and clean chatbot/demo request input
const body = $json.body || $json;
const email = (body.email || '').trim().toLowerCase();
if (!email || !email.includes('@')) {
  throw new Error('Invalid or missing email in demo request');
}
return { json: {
  email,
  firstName: (body.firstName || '').trim(),
  lastName: (body.lastName || '').trim(),
  company: (body.company || '').trim(),
  requestType: body.requestType || 'demo',
  message: body.message || '',
  source: body.source || 'chatbot',
  receivedAt: new Date().toISOString()
} };

// Build enriched lead summary with priority score
const form = $('Validate & Clean Input').first().json;
const lusha = $json;

// Priority scoring
let priority = 0;
const seniority = (lusha.seniority || '').toLowerCase();
if (['c-suite', 'founder', 'owner', 'cxo'].some(s => seniority.includes(s))) priority += 40;
else if (['vp', 'vice president', 'director'].some(s => seniority.includes(s))) priority += 30;
else if (seniority.includes('manager')) priority += 15;

const empMax = Array.isArray(lusha.companySize) ? lusha.companySize[1] : 0;
if (empMax >= 500) priority += 25;
else if (empMax >= 100) priority += 15;
else if (empMax >= 20) priority += 5;

if (form.requestType === 'demo') priority += 15;
if (lusha.primaryPhone) priority += 10;

const isHighPriority = priority >= 50;

return { json: {
  email: form.email,
  firstName: form.firstName || lusha.firstName || '',
  lastName: form.lastName || lusha.lastName || '',
  phone: lusha.primaryPhone || '',
  verifiedEmail: lusha.primaryEmail || '',
  jobTitle: lusha.jobTitle || '',
  seniority: lusha.seniority || '',
  linkedinUrl: lusha.linkedinProfile || '',
  company: form.company || lusha.companyName || '',
  companyDomain: lusha.companyDomain || '',
  industry: lusha.companyMainIndustry || '',
  companySize: empMax,
  revenueRange: lusha.revenueRange || '',
  requestType: form.requestType,
  message: form.message,
  source: form.source,
  priorityScore: priority,
  isHighPriority,
  enrichedAt: new Date().toISOString()
} };

